Here's a well-structured MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher Fetcher, HttpClient Client) CreateFetcher(HttpMessageHandler handler)
    {
        var client = new HttpClient(handler);
        return (new DataFetcher(client), client);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays long enough for cancellation to fire
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert — cancel immediately
        cts.Cancel();
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutExpires_ThrowsTaskCanceled()
    {
        // Arrange — handler that never completes within the token's lifetime
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    /// <summary>Minimal testable handler — avoids needing a mocking library.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<CancellationToken, Task<HttpResponseMessage>> _factory;

        public FakeHandler(HttpResponseMessage response)
            : this(_ => Task.FromResult(response)) { }

        public FakeHandler(Func<CancellationToken, Task<HttpResponseMessage>> factory)
            => _factory = factory;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _factory(cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — test aborts cleanly instead of hanging |
| `Assert.ThrowsExactlyAsync<T>` | Preferred over `[ExpectedException]` — asserts exact type and allows follow-up checks |
| `FakeHandler` | Avoids mocking library; gives full control over response and cancellation behavior |
| `sealed` test class | MSTest best practice for performance |

The `FetchAsync_TimeoutExpires` test is especially important — it verifies your code properly propagates the `CancellationToken` down to `HttpClient.GetAsync`. If someone accidentally drops the token, this test catches it.
